#include <iostream>
#include <string>
using namespace std;

class User {
private:
    string username;

    // СТАТИЧНЕ поле. Лічильник всього класу!
    // Воно ОДНЕ-ЄДИНЕ на всіх. Воно існує навіть коли не створено жодного користувача!
    static int globalUsersCount; 

public:
    // Конструктор
    User(string username) {
        // Вирішуємо конфлікт імен через this->
        this->username = username;
        // Збільшуємо загальний лічильник всього класу
        globalUsersCount++;
    }

    // Деструктор
    ~User() {
        globalUsersCount--;
    }

    // 1. КОНСТАНТНИЙ метод. Гарантує, що не змінить стан об'єкта
    string getUsername() const {
        // username = "error"; // ОШИБКА КОМПІЛЯЦІЇ (Через const)
        return this->username;
    }

    // 2. СТАТИЧНИЙ метод. Не має this! Працює лише із static змінними.
    static int getLobbyCount() {
        return globalUsersCount;
    }
};

// ⚠️ Обов'язкова ініціалізація СТАТИЧНИХ ПОЛІВ зовні класу. 
int User::globalUsersCount = 0;

int main() {
    cout << "Юзерів зараз: " << User::getLobbyCount() << endl; // Можна викликати без об'єкта!

    User* u1 = new User("AlphaGamer");
    User u2("BetaScout");
    User u3("DeltaForce");

    cout << "Знайомтесь: " << u1->getUsername() << endl;
    cout << "Після реєстрації 3 людей Юзерів зараз: " << User::getLobbyCount() << endl;

    cout << "
[Alpha вийшов з гри]" << endl;
    delete u1; // Знищуємо юзера 1

    // У класі 1 лічильник на всіх. Відобразить 2.
    cout << "Юзерів після виходу: " << User::getLobbyCount() << endl;

    return 0;
}
